export const DASHBOARD_ALLOWED_NEXT_PATHS = [
    '/api/slack/connect',
    '/api/end-user-auth/deployment',
    '/api/cli/oauth/authorize',
    '/api/admin-mcp/oauth/authorize',
    '/slack/connect',
];
export const validateDashboardRedirect = (next) => DASHBOARD_ALLOWED_NEXT_PATHS.some((val) => next.startsWith(val));
